INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('microsoft/playwright-cli/playwright-cli', 'playwright-cli', NULL, 'playwright-cli', 'microsoft', 'playwright-cli', 'main', 'https://github.com/microsoft/playwright-cli/blob/main/playwright-cli/SKILL.md', 1, 0, 0, 0, 0, 1778807730, '529ed5e16557a32992dd090b6e3db33e0290f7bd7f559fb375b715f846405f1d', 0);
INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('anthropics/skills:skills\docx', 'docx', 'Use this skill whenever the user wants to create, read, edit, or manipulate Word documents (.docx files). Triggers include: any mention of ''Word doc'', ''word document'', ''.docx'', or requests to produce professional documents with formatting like tables of contents, headings, page numbers, or letterheads. Also use when extracting or reorganizing content from .docx files, inserting or replacing images in documents, performing find-and-replace in Word files, working with tracked changes or comments, or converting content into a polished Word document. If the user asks for a ''report'', ''memo'', ''letter'', ''template'', or similar deliverable as a Word or .docx file, use this skill. Do NOT use for PDFs, spreadsheets, Google Docs, or general coding tasks unrelated to document generation.', 'docx', 'anthropics', 'skills', 'main', 'https://github.com/anthropics/skills/blob/main/skills/docx/SKILL.md', 1, 0, 0, 0, 0, 1779158193, 'f8e0eb6ba0a4c7064e19a1f8f8d5eed8cba48f6c00859e7ef6600a628f6bba33', 0);
INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('anthropics/skills:skills\pptx', 'pptx', 'Use this skill any time a .pptx file is involved in any way — as input, output, or both. This includes: creating slide decks, pitch decks, or presentations; reading, parsing, or extracting text from any .pptx file (even if the extracted content will be used elsewhere, like in an email or summary); editing, modifying, or updating existing presentations; combining or splitting slide files; working with templates, layouts, speaker notes, or comments. Trigger whenever the user mentions "deck," "slides," "presentation," or references a .pptx filename, regardless of what they plan to do with the content afterward. If a .pptx file needs to be opened, created, or touched, use this skill.', 'pptx', 'anthropics', 'skills', 'main', 'https://github.com/anthropics/skills/blob/main/skills/pptx/SKILL.md', 0, 0, 0, 0, 0, 1779158206, '2798c6821e934d5ea0ce4102abd0b3745c00297ff2150add7b197fd6d0a8a6b2', 0);
INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('anthropics/skills:skills\xlsx', 'xlsx', 'Use this skill any time a spreadsheet file is the primary input or output. This means any task where the user wants to: open, read, edit, or fix an existing .xlsx, .xlsm, .csv, or .tsv file (e.g., adding columns, computing formulas, formatting, charting, cleaning messy data); create a new spreadsheet from scratch or from other data sources; or convert between tabular file formats. Trigger especially when the user references a spreadsheet file by name or path — even casually (like "the xlsx in my downloads") — and wants something done to it or produced from it. Also trigger for cleaning or restructuring messy tabular data files (malformed rows, misplaced headers, junk data) into proper spreadsheets. The deliverable must be a spreadsheet file. Do NOT trigger when the primary deliverable is a Word document, HTML report, standalone Python script, database pipeline, or Google Sheets API integration, even if tabular data is involved.', 'xlsx', 'anthropics', 'skills', 'main', 'https://github.com/anthropics/skills/blob/main/skills/xlsx/SKILL.md', 1, 0, 0, 0, 0, 1779158286, 'eb217c1b8086a7ffdf2a66a77f0c83f4f48da508c9009e88a1c3adc2f49aa787', 0);
INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('lewislulu/html-ppt-skill/html-ppt', 'html-ppt', NULL, 'html-ppt', 'lewislulu', 'html-ppt-skill', 'main', 'https://github.com/lewislulu/html-ppt-skill/blob/main/html-ppt/SKILL.md', 0, 0, 0, 0, 0, 1779258017, '358c182cf6dd1b69055c5e9d46e1135fdc1757836c2459ae91bcf2d789b41748', 0);
INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('local:graphify', 'graphify-windows', 'any input (code, docs, papers, images) → knowledge graph → clustered communities → HTML + JSON + audit report. Use when user asks any question about a codebase, project content, architecture, or file relationships — especially if graphify-out/ exists. Provides persistent graph with god nodes, community detection, and BFS/DFS query tools.', 'graphify', NULL, NULL, NULL, NULL, 0, 0, 0, 0, 0, 1779759748, '138ce468854c3166b1eb19331c82e62fa25b0d618e5f85a020e41524cae08ea8', 0);
INSERT INTO "skills" ("id", "name", "description", "directory", "repo_owner", "repo_name", "repo_branch", "readme_url", "enabled_claude", "enabled_codex", "enabled_gemini", "enabled_opencode", "enabled_hermes", "installed_at", "content_hash", "updated_at") VALUES ('anthropics/skills:skills\frontend-design', 'frontend-design', 'Create distinctive, production-grade frontend interfaces with high design quality. Use this skill when the user asks to build web components, pages, artifacts, posters, or applications (examples include websites, landing pages, dashboards, React components, HTML/CSS layouts, or when styling/beautifying any web UI). Generates creative, polished code and UI design that avoids generic AI aesthetics.', 'frontend-design', 'anthropics', 'skills', 'main', 'https://github.com/anthropics/skills/blob/main/skills/frontend-design/SKILL.md', 1, 0, 0, 0, 0, 1779869947, '537c1df9d0c694ecf9139a911f9ad0bd111a7ebc173a55457568459e543fe75b', 0);
